SELECT city_name, average_fare
FROM cities
ORDER BY average_fare DESC;

SELECT AVG(amount) AS average_fare
FROM fares
WHERE city_id = 1;

SELECT city_id, AVG(amount) AS average_fare
FROM fares
GROUP BY city_id;

SELECT COUNT(ride_id) AS total_rides
FROM rides
WHERE city_id = (SELECT city_id FROM cities WHERE city_name = 'Alyssaberg');

SELECT total_rides AS total_rides_completed
FROM drivers
WHERE driver_id = 1;

SELECT city_name
FROM cities
ORDER BY population ASC, area ASC;
